  'person',
  '{"document_kind":"tour_product_full_page_v1","schema_version":7,"slug":"busan-top-attractions-day-tour","locale":"en","product_id":"busan-top-attractions-day-tour","seo":{"pageTitle":"Busan Top Attractions Small-Group Day Tour | AtoC Korea","metaDescription":"10.5-hour Busan small-group classic: Haedong Yonggungsa Temple, Cheongsapo Blue Line, UN Memorial, Gamcheon Culture Village, Jagalchi Market. 3 pickup points.","ogImage":"https://images.unsplash.com/photo-1538669715315-155098f0fb1d?w=1920&q=80","primaryKeywords":["Busan day tour","Haedong Yonggungsa Temple","Gamcheon Culture Village tour","Busan small group tour","Cheongsapo Blue Line Park"]},"catalog_card":{"slug":"busan-top-attractions-day-tour","title":"Busan Top Attractions One-Day Small Group Tour","subtitle":"Busan''s classic seven-stop circuit in one balanced day with three pickup points.","region":"Busan","duration":"10.5 hours","stopsCount":7,"rating":0,"reviewCount":0,"badges":["Small group","First-time friendly","Busan classic","Year-round"],"heroImage":"https://images.unsplash.com/photo-1538669715315-155098f0fb1d?w=1920&q=80","thumbnail":"https://images.unsplash.com/photo-1538669715315-155098f0fb1d?w=600&q=80","priceLabel":"Price varies — confirm at booking","shortCardDescription":"Single-day, 7-stop small-group tour covering Busan''s classic circuit: Haedong Yonggungsa seaside temple, Cheongsapo & Blue Line Park (optional Sky Capsule), local Busan lunch, UN Memorial Cemetery, Gamcheon Culture Village''s painted hillside, and Jagalchi Fish Market. Three pickup points across central Busan; certified English-speaking guide; mini-coach (≈12 max). All site admissions are free; only lunch and optional tickets are paid on-day.","tags":["small_group","busan","first_time","value","year_round"]},"headlineLine1":"Seaside temple, blue-line coast, painted hillside, fish market —","headlineLine2":"Busan''s seven-stop classic in one balanced day","price":{"amountLabel":"","currency":"USD","per":"person","priceNote":"Small-group price not yet confirmed from operator listing. Comparable Busan one-day tours range $41–$70 across operators. Once confirmed, AtoC Korea sale price applies a flat 10% discount."},"hero":{"imageUrl":"https://images.unsplash.com/photo-1538669715315-155098f0fb1d?w=1920&q=80","imagePosition":"center 40%","tagline":"Busan''s most-asked-for seven stops in a single small-group day","pills":["small_group","busan","first_time"],"meta":{"duration":"10.5 hours (08:30 first pickup, ≈ 19:00 last drop)","region":"Busan","stops":"5 stops","rating":0,"ratingStars":0}},"subnavItems":[{"id":"overview","label":"Overview"},{"id":"itinerary","label":"Itinerary"},{"id":"practical","label":"Practical"},{"id":"reviews","label":"Reviews"},{"id":"booking","label":"Booking"}],"glanceItems":[{"icon":"clock","label":"Duration","value":"≈ 10.5 hours (08:30 first pickup, ≈ 19:00 last drop)"},{"icon":"calendar","label":"Best season","value":"Year-round; cherry blossoms at Cheongsapo coast late March–early April"},{"icon":"users","label":"Group Size","value":"Small group (≈12 max), shared mini-coach"},{"icon":"footprints","label":"Walking","value":"Moderate–challenging — Yonggungsa 108 stairs (skippable), Gamcheon hillside, market alleys"},{"icon":"map-pin","label":"Region","value":"Busan (Haeundae area + central Busan)"},{"icon":"ticket","label":"Includes","value":"Round-trip transport, certified guide. Excludes lunch, optional Sky Capsule / Beach Train, optional Busan Tower (₩12,000)."}],"galleryItems":[{"id":"g1","type":"photo","src":"https://images.unsplash.com/photo-1538669715315-155098f0fb1d?w=1200","alt":"Buddhist temple buildings perched on cliffs above the East Sea at Haedong Yonggungsa","caption":"Haedong Yonggungsa — Korea''s most distinctive coastal temple, rebuilt in the 1930s on a 1376 foundation.","location":"Haedong Yonggungsa, Gijang-gun","atmosphere":"Sea spray, granite cliffs, smell of incense"},{"id":"g2","type":"photo","src":"https://images.unsplash.com/photo-1605640840605-14ac1855827b?w=1200","alt":"Open-air beach train running on a coastal track beside a wide sandy beach","caption":"Cheongsapo Blue Line Park — repurposed 1934 railway converted into a 4.8 km coastal beach-train corridor in 2020.","location":"Cheongsapo Blue Line Park, Haeundae","atmosphere":"Open coast, gentle wind, train horn"},{"id":"g3","type":"photo","src":"https://images.unsplash.com/photo-1601171291096-87099c2c4625?w=1200","alt":"Identical headstones in formal rows at the UN Memorial Cemetery","caption":"UN Memorial Cemetery — 2,300+ graves of soldiers from 21 nations, the only UN cemetery in the world.","location":"UN Memorial Cemetery, Nam-gu","atmosphere":"Quiet, formal, contemplative"},{"id":"g4","type":"photo","src":"https://images.unsplash.com/photo-1582719471384-894fbb16e074?w=1200","alt":"Pastel-colored houses cascading down a hillside in Gamcheon Culture Village","caption":"Gamcheon Culture Village — postwar refugee neighborhood transformed into a public-art project in 2009.","location":"Gamcheon Culture Village, Saha-gu","atmosphere":"Bright pastels, narrow alleys, hillside stairs"},{"id":"g5","type":"photo","src":"https://images.unsplash.com/photo-1572883454114-1cf0031ede2a?w=1200","alt":"Rows of fresh seafood on ice at Jagalchi Fish Market","caption":"Jagalchi — Korea''s largest seafood market, run mostly by women across multiple generations.","location":"Jagalchi Market, Jung-gu","atmosphere":"Live tanks, market chatter, sea-salt smell"},{"id":"g6","type":"photo","src":"https://images.unsplash.com/photo-1502175353174-a7a44e84da10?w=1200","alt":"A bowl of dwaeji-gukbap with side dishes on a Busan restaurant table","caption":"Lunch is local — dwaeji-gukbap, milmyeon, or seafood pancake at a Busan restaurant.","location":"Local Busan restaurant","atmosphere":"Quick, no-frills, regional flavors"}],"itineraryStops":[{"number":1,"time":"≈ 09:00","duration":"30 min","name":"Pickup (3 central Busan stations)","category":"Transit / Pickup","description":"Pickup is consolidated at three central Busan transit hubs to keep the day manageable without crisscrossing the city: **Busan Station (Line 1)** for guests staying near the KTX terminal or in the Choryang/Nampo-dong area; **Seomyeon Station (Lines 1 & 2)** — Busan''s busiest subway interchange, central for guests in mid-city hotels around Lotte Hotel Busan or the Seomyeon Medical Street; and **Haeundae Station (Line 2)** for guests in the beachfront resort district near Westin Josun, Park Hyatt, or Signiel Busan. The coach picks up at all three in sequence (typically Busan Station first ~09:00, Seomyeon ~09:15, Haeundae ~09:30) and then heads northeast along the coastal Gwangan Bridge route toward Gijang-gun for the day''s first stop. Total transit from final pickup to Haedong Yonggungsa: ~30-40 minutes depending on traffic. Driver will share a printed Korean-English itinerary card with timings; please be at your pickup point 5 minutes before the scheduled time to keep the day on track for the later UN Memorial Cemetery and Gamcheon stops, which have stricter operating windows.","highlights":["Three pickup options across central Busan (Busan Station, Seomyeon, Haeundae)","Coach is small-group (max ~14 pax)","Total transit to first stop: ~30-40 min","Printed Korean-English itinerary card distributed at pickup"],"timeUsed":["Busan Station pickup (~09:00, ~5 min)","Drive to Seomyeon Station (~10 min)","Seomyeon pickup (~09:15, ~5 min)","Drive to Haeundae Station (~15 min)","Haeundae pickup (~09:30, ~5 min)"],"whyOnRoute":"Three pickup points cover Busan''s three main hotel zones (KTX/Nampo, Seomyeon mid-city, Haeundae beachfront) without forcing guests to transit across the city in the morning. Sequencing northwest→east minimizes coach distance and lands the group at Haedong Yonggungsa around 10:00 — early enough to beat the busiest tour-bus arrivals.","_poi_meta":{"poi_key":"OPS_busan_pickup_central","verified":true,"match":"transit_only","kb_version":"1.15","verified_date":"2026-04-29","sources":["Visit Busan","Busan Metro"]}},{"number":2,"time":"≈ 10:00","duration":"75 min","name":"Haedong Yonggungsa Temple","category":"Buddhist Temple / Coastal","description":"**Haedong Yonggungsa (해동 용궁사) — Korea''s most famous seaside Buddhist temple** — perches on the rocky cliffs of Gijang-gun on Busan''s northeastern coast, one of the very few major Korean temples NOT set in the mountains. Originally founded in **1376 during the Goryeo Dynasty by the great Buddhist teacher Naong Hyegeun (나옹 혜근, 1320-1376)** — a royal consultant and master who would help shape Korean Buddhism into the early Joseon era. Per legend, Naong was practicing asceticism at Bunhwangsa Temple in Gyeongju during a national drought; the East Sea god appeared to him in a dream and told him that building a temple on Bongrae Mountain (the original name of this seaside cliff) would restore the kingdom''s prosperity. Naong founded the temple and named it **Bomunsa**, dedicated to Gwanseum-bosal (관세음보살, the Bodhisattva of Compassion). The temple was destroyed in the **Japanese Imjin Invasion of 1592** and lay in ruins for over 300 years until **Monk Ungang of Tongdosa Temple began reconstruction in the early 1930s**. The current name, **Haedong Yonggungsa (Korean Dragon Palace Temple)**, dates only to **1974** — when Head Monk Jeong-am, during a 100-day prayer (jeong-geon kido), had a vision of the Goddess of Mercy descending on the back of a dragon, emanating multicolor light. The temple was renamed to honor this vision. The visit follows the temple''s signature processional path: through the row of **12 Sibiji-shin (Twelve Zodiac Generals)** at the entry plaza, past the **7-story ''No-Accident Pagoda''** (where drivers leave coin offerings under a stone wheel-shrine), down the famous **108 stone stairs** (representing the 108 delusions of the Buddhist mind) through a small bamboo grove, and out onto the seaside terraces and Daeungjeon main hall. The **Haesu Gwaneum Daebul** (Sea-Goddess of Mercy statue) on the upper cliff is the most photographed view, framing both the temple rooftops and the East Sea. Hours **04:30-19:20 daily, last entry 18:50, FREE admission**. **Buddha''s Birthday (May)** brings Yeondunhoe lantern festival displays.","highlights":["**Founded 1376** by Buddhist master Naong Hyegeun (originally ''Bomunsa'')","One of very few major Korean temples set on the seaside (most are in mountains)","Renamed **Haedong Yonggungsa in 1974** after Monk Jeong-am''s dragon-Goddess vision","**108 stone stairs** = Buddhism''s 108 delusions of the mind","**12 Sibiji-shin (Zodiac Generals)** at entry; ''**No-Accident Pagoda**'' coin shrine","**Haesu Gwaneum Daebul** (Sea Goddess of Mercy) — most photographed cliff view","Daeungjeon main hall restored in 1970 with attention to original colors","Hours daily 04:30-19:20, FREE admission; Buddha''s Birthday (May) lantern festival","**Stone-pillar Buddhist 12 Sibiji-shin Zodiac Generals lineup at the temple gate** — unique among Korean coastal temples"],"timeUsed":["Coach drop-off + walk through vendor lane to entry plaza (~10 min)","Twelve Zodiac Generals + No-Accident Pagoda (~10 min)","108 stairs descent + Daeungjeon main hall + seaside terraces (~30 min)","Haesu Gwaneum statue viewpoint + photo time (~15 min)","Walk back up + reassemble at coach (~10 min)"],"whyOnRoute":"The route''s iconic anchor — the most-photographed temple in Busan, with a 650-year history and a rare Korean seaside Buddhist setting. Picking the 10:00 arrival window lands before the major tour-bus surge (typically 11:00 onward) so the 108-stair descent and the Haesu Gwaneum viewpoint are still walkable without queuing. The northeast-coast location also pairs naturally with Cheongsapo Blue Line Park immediately south — together forming the day''s east-coast cluster before the coach swings back across the city for UN Memorial Cemetery, Gamcheon, and Jagalchi.","visitBasics":{"hours":"Daily 04:30–19:20 (last admission 18:50)","closed":"Open year-round","admission":"Free; private-car parking is paid","walking":"Moderate — 108 steps through pine grove, multiple seaside terraces and stairs"},"convenience":{"restroom":"Available near main entrance and inside complex","parking":"Haedong Yonggungsa Parking Lot (paid, per Visit Busan official)"},"smartNotes":{"photo":"Sunrise rock at the seaward edge; stairs next to Daeungjeon Hall give the classic ocean-and-temple frame; Haesu Gwaneum statue from the upper cliff gives the wide-angle temple-and-East-Sea view","facilities":"Souvenir/snack stalls and small cafe at upper plaza; coastal trail leads further along the rocks","tip":"Side doors for entering halls (front door reserved for monks); Buddha''s Birthday (Apr–May) brings the lantern display; arrive before 10:30 to avoid the worst tour-bus crowds"},"_poi_meta":{"poi_key":"haedong_yonggungsa","verified":true,"match":"exact","kb_version":"1.24","verified_date":"2026-04-29","sources":["Visit Busan","VisitKorea","Wikipedia","Culture Trip","Korean Temple Guide","Korea Tourism Organization Official"]}},{"number":3,"time":"≈ 11:30","duration":"75 min","name":"Cheongsapo & Haeundae Blue Line Park","category":"Coastal Park / Photo Spot","description":"**Haeundae Blue Line Park (해운대 블루라인파크)** is an eco-friendly redevelopment of the **abandoned Donghae Nambu coastal railway**, opened to the public in **2020**. The complex spans 4.8 km of Busan''s most photogenic coastline between **Mipo Station** (near Haeundae Beach) and **Songjeong Station** (near Songjeong Beach), with three ways to experience the same scenery: (1) the **Sky Capsule** — pastel-colored 4-person cabins on an elevated rail 7-10 meters above the coast, running 2.3 km between Mipo and Cheongsapo, (2) the **Beach Train** — a battery-powered eco-train with full-glass ocean-side benches running the entire 4.8 km on 6 stops (Mipo → Dalmaji Tunnel → Cheongsapo → Daritdol Skywalk → Gudeokpo → Songjeong), and (3) the **Busan Green Railway** — a 4.8 km wooden coastal boardwalk that won the 2021 Ministry of Land ''Korea Landscaping Award''. Today''s stop centers on **Cheongsapo (청사포)** — a small fishing-village station that''s one of Busan''s eight scenic views — with two free highlight attractions: (1) the **Cheongsapo Daritdol Skywalk**, opened **August 2017**, a 72.5-m-long, 20-m-high half-moon-shaped glass-bottom observatory in the shape of a blue dragon, FREE admission with slipper covers provided to protect the glass, and (2) the **Cheongsapo Twin Lighthouses** (red + white) and the famous **station crosswalk** that''s gone viral for its Slam Dunk anime resemblance. Guests have free time to (a) ride the **Sky Capsule one-way Mipo→Cheongsapo (₩30,000 for 2 ppl, ₩39,000 for 3, ₩44,000 for 4)** if booked in advance, or (b) walk the wooden Green Railway ~30 min from Mipo to Cheongsapo. **Sky Capsule reservations should be made through the official bluelinepark.com or Klook 1-2 weeks in advance** for sunset slots; tour staff can assist with on-site automated kiosks if available.","highlights":["**Haeundae Blue Line Park opened 2020** on disused Donghae Nambu coastal railway","**Sky Capsule** (2.3 km elevated) + **Beach Train** (4.8 km, 6 stops) + Green Railway boardwalk","**Cheongsapo Daritdol Skywalk** (Aug 2017): 72.5-m glass-bottom skywalk, 20m above sea — **FREE**","**Sky Capsule pricing**: ₩30,000 (2 ppl) / ₩39,000 (3) / ₩44,000 (4) one-way","Cheongsapo Twin Lighthouses (red + white) — Slam Dunk-style anime crosswalk","Beach Train ₩7,000 single / ₩10,000 re-board once","Cheongsapo = one of Busan''s **eight scenic views**","World''s first battery-charged eco-friendly sightseeing train","**Sky Capsule pricing 2026**: 2pax ₩30,000 / 3pax ₩39,000 / 4pax ₩44,000 one-way; **Beach Train** runs 4.8 km / 6 stops on the Donghae Nambu line opened in 2020"],"timeUsed":["Drop-off at Cheongsapo Station (~5 min)","Daritdol Skywalk walk-out + glass-floor experience (~25 min)","Twin lighthouses + crosswalk photo spots (~15 min)","Optional Sky Capsule one-way OR seafood snack at village stalls (~25 min)","Reassemble at coach (~5 min)"],"whyOnRoute":"The route''s **most-Instagrammed** segment — the pastel Sky Capsule has become a viral Korea-travel symbol since 2020. Cheongsapo is chosen over Mipo or Songjeong because the Daritdol Skywalk + Twin Lighthouses + village atmosphere all sit within a 600-m walking radius of the station, fitting cleanly inside a 75-min stop. Sky Capsule is OPTIONAL because the on-the-day boarding queue can run 30+ min and would otherwise jeopardize the lunch + UN Cemetery + Gamcheon timing later in the day; guests who must ride should book the sunset Mipo→Cheongsapo slot independently.","visitBasics":{"hours":"Sky Capsule and Beach Train ~09:30–18:30 (extended to 20:30 in summer); Cheongsapo Daritdol Skywalk free 24h","closed":"Operations weather-dependent; check the day of","admission":"Free area; Sky Capsule 30,000 KRW (2 ppl) / 39,000 (3) / 44,000 (4) one-way; Beach Train ₩7,000 single / ₩10,000 re-board once","walking":"Easy along the wooden Green Railway boardwalk (Mipo↔Cheongsapo 2.3 km, ~30 min); flat at stations"},"convenience":{"restroom":"Available at Mipo, Cheongsapo and Songjeong stations","parking":"Public lots near Mipo Station and Cheongsapo Station (paid)"},"smartNotes":{"photo":"Cheongsapo Station crosswalk for the famous Slam Dunk-style frame; Daritdol Skywalk for glass-bottom sea view; Mipo→Cheongsapo direction on Sky Capsule has the best afternoon light","facilities":"In-person ticketing at Mipo, Cheongsapo and Songjeong only (automated kiosks at Dalmaji Tunnel, Daritdol, Gudeokpo); convenience store and food at Mipo plaza","tip":"Sky Capsule books out fast at sunset slots — reserve 1-2 weeks in advance via Klook or bluelinepark.com; bring backup for refunds — no refunds/changes for missed slots"},"_poi_meta":{"poi_key":"cheongsapo_blue_line_park","verified":true,"match":"exact","kb_version":"1.24","verified_date":"2026-04-29","sources":["Blue Line Park official","Visit Busan","Soul of Seoul","KoreaToDo","Tara O''Reilly travel","Busan Metropolitan City Tourism"]}},{"number":4,"time":"≈ 13:00","duration":"60 min","name":"Lunch (local Busan restaurant)","category":"Lunch / Local Cuisine","description":"Lunch is at a coach-friendly local restaurant en route from Haeundae back across central Busan toward UN Memorial Cemetery in Nam-gu. Two typical options depending on coach routing and group preference: (1) **Dwaeji Gukbap (돼지국밥)** — Busan''s signature pork-bone broth rice soup, the city''s working-class comfort food since the Korean War refugee era, served with kkakdugi radish kimchi, saeujeot shrimp paste, buchu chives, and rice (~9,000-12,000 KRW per bowl); recommended in the Seomyeon or Daeyeon-dong neighborhoods, or (2) **Milmyeon (밀면)** — Busan''s wheat-flour cold noodles, an adaptation of North Korean Pyongyang naengmyeon by refugees who couldn''t find buckwheat in wartime Busan, served in chilled beef-broth or in spicy bibim style (~8,000-11,000 KRW). Both are **regional specialties unique to Busan and not commonly found in Seoul**. Lunch is at the guest''s own expense; vegetarian and halal-friendly options are limited at most dwaeji-gukbap restaurants — please notify the guide at booking if dietary accommodations are needed and a separate restaurant (typically a bibimbap or hansik buffet) will be substituted. Total time ~60 min including parking + ordering + eating + restroom + boarding the coach.","highlights":["**Dwaeji-gukbap** (Busan pork-bone soup) or **milmyeon** (Busan cold wheat noodles) — both regional specialties","Both dishes have Korean War refugee origins unique to Busan","Typical price ~₩8,000-12,000 per dish (own expense)","Vegetarian / halal-friendly substitution available on request at booking","60-min stop — efficient enough to keep UN Cemetery + Gamcheon on schedule"],"timeUsed":["Coach drop-off + walk to restaurant (~5 min)","Order + meal (~40 min)","Restroom + reassemble at coach (~15 min)"],"whyOnRoute":"Lunch is timed at 13:00 to bridge the morning''s east-coast cluster (Haedong Yonggungsa + Cheongsapo) and the afternoon''s central Busan cluster (UN Memorial Cemetery + Gamcheon + Jagalchi). The choice of dwaeji-gukbap or milmyeon over generic Korean BBQ reflects the route''s local-culture priority — both dishes are Busan-specific Korean War heritage cuisine that guests are unlikely to encounter on a Seoul-only Korea trip. Restaurant choice on the day depends on coach routing and current restaurant availability; tour guide will confirm at the morning briefing.","_poi_meta":{"poi_key":"OPS_busan_lunch","verified":true,"match":"lunch_placeholder","kb_version":"1.15","verified_date":"2026-04-29","sources":["Visit Busan","Busan Metropolitan Government cuisine guide"]}},{"number":5,"time":"≈ 14:15","duration":"60 min","name":"UN Memorial Cemetery in Korea","category":"Memorial / War History","description":"**The UN Memorial Cemetery in Korea (재한유엔기념공원, UNMCK)** is the **only United Nations memorial cemetery anywhere in the world** — established January 18, 1951 by the UN Command during the Korean War, dedicated April 6, 1951 by US General Matthew Ridgway, and formally donated to the United Nations by the Republic of Korea in **1959** in gratitude for the UN forces who died defending South Korea. **22 sending nations participated in the Korean War (1950-1953)** under the UN flag — 16 nations sent combat troops + 5 sent medical aid + 1 sent observers. Initially up to **11,000 graves** were here; most fallen were repatriated post-armistice, leaving today **2,300 graves from 11 countries** (UK, US, Türkiye, Canada, Australia, Netherlands, France, Norway, South Korea, New Zealand, South Africa). The visit walks the cemetery''s main monumental sequence: (1) the **Main Gate** (designed by Korean architect Kim Joong-up, built by Busan City in 1966 — the eight roof-supporting pillars symbolize the moment and eternity of soldiers'' standing watch); (2) the **Memorial Service Hall** featuring a 12-minute documentary in English/Korean on the cemetery''s history; (3) the **Symbolic Area** where the **22 sending-state flags + Korean + UN flag** fly daily; (4) the **Wall of Remembrance**, completed **2006**, with all **40,896 UN casualty names inscribed on 140 marble panels** — many veterans'' relatives find their ancestors here for the first time; and (5) the **US Korean War Memorial**, dedicated **2013** with the Frank Gaylord sculpture commissioned by the American Battle Monuments Commission. **Hours: 09:00-18:00 (May-Sep) / 09:00-17:00 (Oct-Apr); FREE; 100% wheelchair-accessible**. Annual **''Turn Toward Busan'' silent ceremony** Nov 11 11:00 AM, where the world turns symbolically toward this cemetery.","highlights":["**Only UN memorial cemetery in the world** — established January 1951 by UN Command","Land donated by Republic of Korea to United Nations in **1959**","**22 sending nations** under UN flag during Korean War (1950-1953)","Today **2,300 graves from 11 nations** (after most repatriations post-armistice)","**Wall of Remembrance (2006)**: 40,896 UN casualty names on 140 marble panels","Main Gate designed by **Korean architect Kim Joong-up (1966)**","**''Turn Toward Busan'' ceremony** annually Nov 11 at 11:00 AM — global silent tribute","Hours daily 09:00-18:00 May-Sep / 09:00-17:00 Oct-Apr; FREE; 100% wheelchair-accessible","**''Turn Toward Busan'' ceremony November 11 at 11:00 AM** — only UN memorial cemetery in the world hosts this annual moment of silence honoring 22 sending nations"],"timeUsed":["Coach drop-off + walk to Memorial Hall (~5 min)","12-minute Korean War documentary + introduction (~15 min)","Symbolic Area (22 flags) + Wall of Remembrance (~20 min)","Walk grounds + return to coach (~20 min)"],"whyOnRoute":"The route''s **moral counterweight** — Busan''s identity is inseparable from its role as the only Korean city the North Korean Army never captured during the war (population spiked from 880,000 to 1.4 million as refugees flooded south), and Gamcheon''s hillside refugee shanties + Jagalchi''s ''ajumma'' fish-vendor culture both trace directly to this same Korean War narrative. Visiting UNMCK before Gamcheon and Jagalchi gives guests the historical context that makes the rest of the day''s stops more than just photo opportunities. The 14:15 arrival also lands well inside the May-Sep evening 18:00 close (or Oct-Apr 17:00 close).","visitBasics":{"hours":"Daily 09:00–18:00 (May–Sep) / 09:00–17:00 (Oct–Apr)","closed":"Open year-round","admission":"Free","walking":"Easy — flat grass paths and paved walkways across 14 ha of grounds; 100% wheelchair-accessible"},"convenience":{"restroom":"Available at Memorial Service Hall and visitor center","parking":"On-site lot — free for first 90 min, then ₩1,200/hr"},"smartNotes":{"photo":"Wall of Remembrance (40,896 names on 140 marble panels) and the Symbolic Area where the 22 sending-state flags fly","facilities":"Memorial Service Hall, Memorabilia Hall, UN Forces Monument, US Korean War Memorial (2013 Frank Gaylord sculpture), and adjacent UN Peace Memorial Hall","tip":"Watch the 12-minute documentary in Memorial Service Hall first (English available); dress neatly, keep voices low, and no food on the grounds; ground is sacred — no climbing on graves or grass between markers"},"_poi_meta":{"poi_key":"un_memorial_cemetery","verified":true,"match":"exact","kb_version":"1.24","verified_date":"2026-04-29","sources":["UNMCK official","Wikipedia","ABMC","Visit Busan","CNN","VisitKorea","UN Memorial Cemetery in Korea Official Site"]}},{"number":6,"time":"≈ 15:30","duration":"75 min","name":"Gamcheon Culture Village","category":"Cultural Village / Mural Art","description":"**Gamcheon Culture Village (감천문화마을)** — nicknamed both **''Korea''s Machu Picchu''** and **''Korea''s Santorini''** — is a hillside neighborhood in Saha-gu, west Busan, whose pastel-painted houses cascade down in stepped rows over the slope. The settlement began in the **1920s-1930s** when the Busan administration relocated working-class residents away from the port. The village''s character was set in **1955** when **~800 families (about 4,000 people) of the Taegeukdo religious community** — a uniquely Korean syncretic religion blending Buddhist, Confucian, and yin-yang elements, founded by **Jo Cheol-je** during the Japanese colonial period — settled here as Korean War refugees fleeing the North. The Taegeukdo philosophy of ''**allowing others to prosper**'' directly shaped the village''s most distinctive feature: houses are intentionally tiered so that **no roof blocks the view of the house behind it**, with the entire community visible to the sky and the sea. Gamcheon remained one of Busan''s poorest neighborhoods until **2009**, when the Korean Ministry of Culture launched the **''Dreaming of Machu Picchu in Busan''** public-art revitalization project, followed by the **''Miro Miro'' (maze) project in 2010** — adding 22+ commissioned murals, sculptures, and art installations including the iconic **''Little Prince and Fox'' bench** at the Sky Garden viewpoint. Gamcheon won the **2012 UN-HABITAT Asian Townscape Award** and now welcomes **~1.4 million visitors annually**. The visit follows the village''s signature stamp-map walking route: from the entrance at the **Tourist Information Center**, up to **Sky Garden viewpoint** for the panoramic rainbow-roof shot, then down through the labyrinthine alleys past murals, hanbok rental shops, craft workshops, and small cafes. **The village is a living residential community** — quiet voices required, no drones, no flash photography into homes, and rubbish carried out. Hours **09:00-18:00 Mar-Oct / 09:00-17:00 Nov-Feb (info center)**; **village itself open 24h, FREE entry**.","highlights":["**''Korea''s Machu Picchu'' / ''Korea''s Santorini''** — UN-HABITAT Asian Townscape Award 2012","Origins: **1920s-1930s** Busan administration relocation + **1955 Taegeukdo refugees** (~800 families)","**Taegeukdo philosophy of ''allowing others to prosper''** = no house blocks the view behind it","**2009 ''Dreaming of Machu Picchu'' + 2010 ''Miro Miro''** Ministry of Culture public-art projects","**''Little Prince and Fox'' bench** at Sky Garden — the village''s most-photographed spot","**~1.4 million visitors annually** since the public-art revitalization","**Living residential community** — quiet voices, no drones, no flash into homes","Free village entry; optional Stamp Map ~₩2,000","**UN-HABITAT Asian Townscape Award 2012** — recognition of the 2009 ''Dreaming of Machu Picchu'' art project that transformed the 1955 Taegeukdo refugee settlement into Busan''s signature mural village"],"timeUsed":["Coach drop-off at Public Parking Lot 2 + walk to entrance (~5 min)","Tourist Information Center + Stamp Map purchase (~10 min)","Sky Garden viewpoint + Little Prince bench (~25 min)","Alley walk past murals + small cafe pause (~25 min)","Reassemble at coach (~10 min)"],"whyOnRoute":"The route''s **most colorful and unique** stop — there is no other neighborhood like this anywhere in Korea. The Korean War refugee narrative directly threads from UN Memorial Cemetery (the moral memorial) → Gamcheon (the lived consequence: refugee settlement that became a community) → Jagalchi (the economic consequence: ajumma fish-vendors supporting their families). The 15:30 arrival lands ahead of the 18:00 info-center close while still giving guests ~1 hour of golden-hour light over the rainbow rooftops, the village''s most photogenic time.","visitBasics":{"hours":"Daily 09:00–18:00 (Mar–Oct) / 09:00–17:00 (Nov–Feb); some shops/cafes keep their own hours","closed":"Open year-round (a living residential community)","admission":"Free village entry; optional Stamp Map ≈ 2,000 KRW","walking":"Strenuous — very steep alleys and stairs; not stroller- or wheelchair-friendly in many sections"},"convenience":{"restroom":"Public restrooms at the Tourist Information Center and around the main viewpoints","parking":"Gamcheon Public Parking Lot 2 (paid)"},"smartNotes":{"photo":"Little Prince and Fox bench (long queue) and Haneul Maru / Sky Garden Observatory for the sweeping rainbow-roof and bay view","facilities":"Hanbok rental, craft workshops, Korean candy stalls, cafes; small village museum at the entrance; the stamp map is the easiest way to navigate","tip":"Residents live here — keep voices down, no drones, take rubbish with you; wear grippy shoes for the steep lanes; afternoon golden hour ~16:00-17:00 is the village''s best light"},"_poi_meta":{"poi_key":"gamcheon_culture_village","verified":true,"match":"exact","kb_version":"1.24","verified_date":"2026-04-29","sources":["Wikipedia","CNN","Visit Busan","Hapskorea","Columban Society","Lifeguin","Busan Cultural Foundation"]}},{"number":7,"time":"≈ 17:15","duration":"60 min","name":"Jagalchi Fish Market","category":"Fish Market / Local Culture","description":"**Jagalchi Market (자갈치시장)** — **Korea''s largest seafood market** and one of Busan''s ten landmarks — sits on the Nampo Port waterfront in Jung-gu, a 7-min walk from Jagalchi Station (Line 1) or Nampo Station. The name **''Jagalchi''** comes from **''jagal'' (자갈, gravel)**, after the pebbly shoreline that once lined the area. The market''s modern character was forged after the **Korean War (1950-1953)**: when many men were away fighting or had been lost in combat, **widowed and displaced women — the legendary ''Jagalchi Ajumma'' (자갈치 아주머니)** — became their families'' breadwinners by selling fish on wooden boxes along the pierside. The ajumma have been the **economic and cultural soul of Busan ever since**, embodying both the city''s post-war recovery story and Korea''s ''**jeong (정)**'' culture of long-term personal trust between vendor and customer. The current modern **seagull-shaped main building reopened in 2006** and houses ~400 vendors across 66,000 m² gross floor area: **1F** is the live-seafood market (octopus, snow crab, abalone, sea squirt, live hagfish, mackerel, sea cucumbers, hoe-grade flounders) where guests can **buy fresh seafood by weight then take it upstairs to a 2F restaurant for a small cooking fee** — that''s the local way to eat at Jagalchi. **2F** is the sashimi-and-restaurant level. The dried-seafood section (anchovies, sea laver, kelp, dried squid) extends along the outdoor pier and is the most photogenic for travel snapshots. **Hours 05:00-22:00 daily; CLOSED 1st & 3rd Tuesdays of each month**. **Annual Jagalchi Cultural Tourism Festival** every October. The visit time is deliberately at the market''s late-afternoon lull (post-lunch crowd, pre-evening drinking crowd) to make the lanes and rooftop **Sky Park** comfortably walkable.","highlights":["**Korea''s largest seafood market** — covers 66,000 m² with ~400 vendors","**''Jagalchi''** = ''gravel'' (자갈) for the original pebbly shoreline","**''Jagalchi Ajumma''** = post-Korean War widowed/displaced women fish vendors — Busan''s icon","**Buy fish 1F → cook upstairs 2F** with small cooking fee = the local way","**Modern seagull-shaped building reopened 2006**","Annual **Jagalchi Cultural Tourism Festival** in October","Outdoor pier and Sky Park (5F when open) for waterfront photos","Hours daily 05:00-22:00; **CLOSED 1st & 3rd Tuesdays** of each month","**Modern seagull-shaped main building reopened 2006** spanning ~66,000 m² with ~400 vendors; **closed 1st & 3rd Tuesdays** of each month (operational note critical for itinerary planning)"],"timeUsed":["Coach drop-off + walk to main building (~5 min)","1F live-seafood walk-through with guide commentary (~20 min)","Outdoor pier + dried-seafood lanes (~15 min)","Optional sashimi snack OR Sky Park rooftop (~15 min)","Reassemble at coach + drop-off at pickup points (~5 min)"],"whyOnRoute":"The route''s **culinary closing scene** — Busan''s identity is built on seafood the way Seoul''s is built on royal Joseon palace cuisine, and Jagalchi is the single-most-essential expression of that. The 17:15 visit lands deliberately between the lunch crowd''s tail-end and the dinner-drinking surge that fills the 2F sashimi restaurants from 18:30 onward — making the lanes walkable and photogenic. Pairing Jagalchi as the day''s final stop also lets the coach efficiently drop guests at Jagalchi/Nampo (Line 1) for those wanting to continue independently into Nampo-dong''s BIFF Square or Gukje Market in the evening, or back to Busan Station / Seomyeon / Haeundae for those returning to hotels.","visitBasics":{"hours":"Daily 05:00–22:00 (vendor hours vary; live-fish section officially 06:00–22:00)","closed":"1st and 3rd Tuesdays of every month","admission":"Free entry; pay-as-you-go for seafood and 2F cooking-fee","walking":"Moderate — ground floor flat (wet, can be slippery); stairs to 2F sashimi/restaurant level"},"convenience":{"restroom":"Available inside the main building on each floor","parking":"Basement lot at the main building, ₩700 / 10 min"},"smartNotes":{"photo":"Outdoor pier behind the building for the harbor-and-fishing-boat shot; Jagalchi ajummas at the live-fish stalls (always ask permission first)","facilities":"1F live seafood, 2F sashimi & restaurants, dried-fish section, rooftop Sky Park (when open), Sashimi Center buffet on 5F","tip":"Buy the fish on 1F, then bring it upstairs to a 2F restaurant and pay a small cooking fee — that''s the local way; address 52 Jagalchihaean-ro, Jung-gu; floor is wet — closed-toe shoes recommended; cash works better than cards at smaller stalls"},"_poi_meta":{"poi_key":"jagalchi_market","verified":true,"match":"exact","kb_version":"1.24","verified_date":"2026-04-29","sources":["VisitKorea","Wikipedia","Visit Busan","Hungry Pursuit","Emma Jane Explores","Jagalchi.org","Korean Heritage Service / Cultural Heritage Administration"]}}],"routeFlowStops":[{"name":"Pickup (3 central Busan stations)","type":"origin","theme":"Departure"},{"name":"Haedong Yonggungsa Temple","type":"primary","theme":"Seaside temple"},{"name":"Cheongsapo & Blue Line Park","type":"primary","theme":"Coast & beach train"},{"name":"Lunch (local Busan restaurant)","type":"meal","theme":"Meal"},{"name":"UN Memorial Cemetery","type":"primary","theme":"Memorial"},{"name":"Gamcheon Culture Village","type":"primary","theme":"Art village"},{"name":"Jagalchi Fish Market","type":"return","theme":"Seafood market"}],"routePhases":[{"phase":"Coastal morning","duration":"≈ 3 hours","description":"Pickup (60 min window) and drive to Yonggungsa Temple, then south to Cheongsapo Blue Line Park."},{"phase":"Lunch break","duration":"≈ 1 hour","description":"Mid-day at a local Busan restaurant (dwaeji-gukbap, milmyeon, or seafood pancake)."},{"phase":"Memorial + village","duration":"≈ 3.5 hours","description":"UN Memorial Cemetery (60 min) then Gamcheon Culture Village''s photo loop (120 min)."},{"phase":"Market close","duration":"≈ 1.5 hours","description":"Jagalchi Market browse and streetfood (75 min); central-Busan drop-offs follow."}],"routeShapeIntro":{"title":"How this Busan day moves","subtitle":"Northeast coastal temple first, blue line park, UN memorial mid-day, Gamcheon village with lunch, then close at Jagalchi market in central Busan. 08:30 to 18:00."},"whyTourWorks":{"bestFor":["First-time Busan visitors","Adult families and couples","Travelers with one full day in Busan","Cultural and food-curious travelers"],"lessIdealFor":["Travelers who want minimal walking / minimal stairs","Stroller-heavy groups (Gamcheon hillside)","Travelers needing tight evening flight buffer (return up to 19:00)"],"routeLogicSections":[{"title":"Pacing & geography","icon":"sun","iconBg":"bg-amber-50/80","iconColor":"text-amber-600","items":[{"label":"Northeast first while energy is fresh","detail":"Yonggungsa is in Gijang-gun, the northeast extremity of the route, and is scheduled first because the 108 stairs and the cliff path are the day''s most active stop. Doing it before lunch keeps the rest of the day on flatter ground and lower-energy attractions."},{"label":"Coast then memorial then village","detail":"The route trades scenery for context for color: bright coastal openers, a quiet memorial mid-day, then Gamcheon''s painted hillside as the visual peak. Each section is photo-distinct."},{"label":"Central-Busan close","detail":"Jagalchi Market is in central Busan — guests staying near Nampo-dong can disembark at the final stop and continue exploring; others ride back to their pickup station along the standard return route."}]},{"title":"Why this works in 10.5 hours","icon":"clock","iconBg":"bg-pink-50/80","iconColor":"text-pink-600","items":[{"label":"Six substantive stops + lunch","detail":"Two coastal sites, one memorial, one village (extended), one market, plus lunch — each block long enough to feel real, none rushed. Compares favorably to 5-stop tours that drop either Yonggungsa (too far) or Cheongsapo (too new) to fit."},{"label":"Mostly outdoor, market closes indoor","detail":"≈80% outdoor across the day; Jagalchi is the only fully indoor block. Works in most weather conditions; the market gives a covered finish in a late-afternoon shower."},{"label":"Three pickup locations","detail":"Pickup at Seomyeon, Busan Station, or Haeundae — accessible from most central-Busan accommodations. Choose the exit closest to your hotel; tour duration adjusts ±30 min based on pickup point."}]},{"title":"Trade-offs honestly","icon":"info","iconBg":"bg-sky-50/80","iconColor":"text-sky-600","items":[{"label":"Yonggungsa has 108 stairs (skippable)","detail":"The 108 steps go down to the temple platform. Upper viewing areas are accessible without descending. If the climb back up is a concern, the viewpoint above the temple is the recommended turnaround."},{"label":"Gamcheon''s alleys are steep — slippery in rain","detail":"Wear shoes with grip and pace yourself uphill. The main photo zone is reachable on a relatively gentle path; deeper exploration requires the steepest stairs."}]}]},"practicalAccordionItems":[{"id":"pickup","title":"Pickup & drop-off","preview":"Three pickup points along Busan Subway: Seomyeon Station Exit 4 (08:30), Busan Station…","content":["Three pickup points along Busan Subway: Seomyeon Station Exit 4 (08:30), Busan Station Exit 4 — not the KTX gate (08:50), Haeundae Station Exit 5 (09:30).","Drop-offs in sequence: Nampo-dong/Jagalchi ≈17:50, Busan Station ≈18:10, Seomyeon ≈18:30, Haeundae ≈19:00.","Your effective tour duration depends on pickup point: Seomyeon ≈10 h, Haeundae ≈9.5 h."]},{"id":"what-to-bring","title":"What to wear & bring","preview":"Comfortable walking shoes with grip — Gamcheon''s hillside alleys and Yonggungsa''s 108…","content":["Comfortable walking shoes with grip — Gamcheon''s hillside alleys and Yonggungsa''s 108 stairs both need traction.","Light layer for AC vehicle and the sea breeze at Yonggungsa.","Camera or smartphone (Gamcheon and Cheongsapo are the photo highlights).","Cash or card for lunch (₩10,000–₩20,000), the optional Sky Capsule / Beach Train tickets at Cheongsapo, and the optional Busan Tower observatory."]},{"id":"weather-policy","title":"Weather policy","preview":"Year-round operation.","content":["Year-round operation.","Light rain: tour runs as scheduled — Yonggungsa under rain has its own atmosphere, and Gamcheon''s alleys remain navigable.","Heavy rain or storms: the operator may reroute (Yonggungsa''s lower temple area becomes slippery, Gamcheon''s stairs unsafe) and offers rebooking with advance notice.","Typhoon-level weather: full refund or rebooking on the operator''s side."]},{"id":"inclusions","title":"What''s included","preview":"Pickup and drop-off at three Busan stations, air-conditioned mini-coach transport,…","content":["Pickup and drop-off at three Busan stations, air-conditioned mini-coach transport, licensed English-speaking guide.","Excluded: lunch (₩10,000–₩20,000), optional Cheongsapo Sky Capsule (₩30,000–₩35,000 per 4-person capsule) or Beach Train (₩7,000), optional Busan Tower observatory (₩12,000).","All other site admissions are free: Yonggungsa, UN Cemetery, Gamcheon village, Jagalchi Market."]},{"id":"language","title":"Language","preview":"Primary tour language: English.","content":["Primary tour language: English.","Chinese-speaking guide available on request — book 3+ days ahead.","Korean is spoken throughout the day for menus, signage, and stall interactions; the guide handles translation."]},{"id":"walking","title":"Walking & terrain","preview":"Moderate–challenging.","content":["Moderate–challenging.","Yonggungsa has 108 stone steps down to the temple (skippable — upper viewing platforms exist).","Gamcheon is a hillside village with steep alleys and stairs throughout the photo route — traction shoes essential.","UN Cemetery is flat.","Jagalchi indoor market is flat but crowded.","Total walking ≈4–5 km plus stairs."]}],"practicalWeatherStatic":{"today":{"temp":"—","label":"See seasonal notes"},"tomorrow":{"temp":"—","label":"See seasonal notes"},"_seasonalSummary":"Busan: Korea''s southernmost major city, milder and wetter than Seoul. Mild winters (5–10 °C), humid summers, peak rainfall in July monsoon."},"seasonalVariations":[{"season":"Spring (Mar–May)","description":"Cherry blossoms at Cheongsapo coast and along the Haeundae Blue Line Park path in late March / early April. Busan''s blossom timing is 7–10 days ahead of Seoul."},{"season":"Summer (Jun–Aug)","description":"Long daylight; coastal stops stay cooler than inland. July monsoon may shorten outdoor time. Yonggungsa morning visit avoids heat."},{"season":"Autumn (Sep–Nov)","description":"Clearest visibility, warmest sea — best season overall. Foliage in late October. Cheongsapo coastal walk most comfortable."},{"season":"Winter (Dec–Feb)","description":"Fewer crowds; clear sea views; mild for Korea (Busan winter lows 5–10 °C). Yonggungsa New Year''s Day sunrise is a major event — book early."}],"bookingTrustItems":[{"icon":"check-circle","title":"Licensed local","description":"Busan-licensed guiding","iconBg":"bg-emerald-50/80","iconColor":"text-emerald-600"},{"icon":"users","title":"Small group","description":"≈12 guests max","iconBg":"bg-pink-50/80","iconColor":"text-pink-600"},{"icon":"shield","title":"All-inclusive entry","description":"Major admissions covered","iconBg":"bg-sky-50/80","iconColor":"text-sky-600"}],"bookingSupportSteps":[{"timing":"Immediately","title":"Instant Confirmation","detail":"Booking confirmation with itinerary summary"},{"timing":"Day before","title":"Pickup Details","detail":"Exact pickup location and vehicle info via WhatsApp"},{"timing":"Morning of","title":"Pickup Confirmation","detail":"Driver checks in 10 minutes before arrival"},{"timing":"During tour","title":"On-tour Support","detail":"Direct line to operations"},{"timing":"End of day","title":"Flexible Drop-off","detail":"Choose drop-off at Nampo-dong, Busan Station, Seomyeon, or Haeundae"},{"timing":"After tour","title":"Review & Followup","detail":"Optional review and follow-up"}],"staticQuestions":[{"id":"first-time","question":"Is this good for first-time visitors to Busan?","answer":"Yes — this is the classic Busan one-day route covering temple, coast, memorial, art village, and market. If you have one day in Busan and want the city''s most-photographed and most-asked-about stops in one trip, this is the right choice."},{"id":"stairs","question":"How many stairs at Yonggungsa?","answer":"108 stone steps down from the upper plaza to the temple platform — the single steepest physical demand of the day. The 108 number is symbolic (the 108 worldly defilements in Buddhist teaching). Skip option: stay at the upper viewing area, which gives a strong photo of the temple from above without the descent."},{"id":"gamcheon-walking","question":"Is Gamcheon''s hillside hard?","answer":"Moderate to challenging — the alleys are steep, narrow, and stair-heavy. Wear shoes with grip; take it slow and use the stair handrails. The main photo zone (Little Prince statue, mosaic stairs) is reachable on a relatively gentle path; deeper exploration requires the steepest stairs. The 2-hour stop accommodates a slow pace."},{"id":"sky-capsule","question":"Is the Sky Capsule at Cheongsapo included?","answer":"No — it''s an optional separate ticket. Sky Capsule (₩30,000–₩35,000 per 4-person capsule) and the Beach Train (₩7,000 round-trip) both run on the converted 4.8 km Blue Line Park route. Sky Capsule sells out on weekends — book 2–3 days ahead directly with the operator. Beach Train can usually be bought on the day."},{"id":"lunch","question":"Is lunch included? What are the options?","answer":"No — lunch is paid by the guest (₩10,000–₩20,000 per person). Typical local choices: dwaeji-gukbap (Busan-style pork-and-rice soup), milmyeon (cold wheat noodles, the city''s signature summer dish), haemul-pajeon (seafood-and-scallion pancake), or a bibimbap set. Vegetarian, halal, and gluten-free options are possible with advance notice — please advise at booking."},{"id":"kids","question":"Is this suitable for children?","answer":"Yes, age 6 and up. Yonggungsa stairs and Gamcheon hillside are the main physical considerations; both have skip / shortcut options. Kids tend to like the Beach Train at Cheongsapo (if booked) and the live-fish floor at Jagalchi."},{"id":"seniors","question":"Is this OK for seniors?","answer":"Considerably challenging due to Yonggungsa''s stairs and Gamcheon''s hillside. Active seniors are fine and the Beach Train option simplifies Cheongsapo; mobility-limited travelers should consider a private Busan tour with route adjustments."},{"id":"language","question":"What languages does the guide speak?","answer":"English primarily. Chinese-speaking guide available on request — book 3+ days ahead for Chinese. The guide handles all menu translation and stall interactions during the day."},{"id":"pickup","question":"Where do you pick up?","answer":"Three central-Busan stations: Seomyeon Station Exit 4 (08:30), Busan Station Exit 4 — not the KTX gate (08:50), Haeundae Station Exit 5 (09:30). Choose the exit closest to your hotel at booking."},{"id":"drop-off","question":"Where do you drop off?","answer":"Multiple drop-off points along the return route: Nampo-dong / Jagalchi (≈17:50, the final attraction), Busan Station (≈18:10), Seomyeon (≈18:30), Haeundae (≈19:00). Guests staying near Jagalchi/Nampo can disembark there and continue exploring."},{"id":"compare","question":"How does this compare with other Busan tours?","answer":"This is the classic 7-stop one-day route. For Gyeongju add-on (UNESCO content), see our Busan-Gyeongju day trip. For private/customizable routes with door-of-hotel pickup, see our private Busan tour. For a cruise-port version with terminal pickup, see our Busan cruise excursion."},{"id":"yonggungsa-best-time","question":"What''s the best time to visit Yonggungsa?","answer":"On this tour: ≈10:00 — early enough to beat the noon coach groups, late enough that the morning sun is on the temple''s east-facing courtyard for photos. For independent travel: New Year''s Day sunrise is the most-attended time of year (the temple opens early for it); late-April Buddha''s Birthday is the most lantern-decorated."},{"id":"tower-included","question":"Is the Busan Tower observatory in this tour?","answer":"No — Busan Tower / Yongdusan Park is not on this 7-stop circuit. The route prioritizes Gamcheon and Cheongsapo as the visual stops. If Busan Tower is a priority for you, see our Busan cruise excursion (which includes Yongdusan Park + optional tower ticket) or our private Busan tour."},{"id":"walking","question":"How much walking is there?","answer":"≈4–5 km plus the 108 stairs at Yonggungsa (skippable) and the Gamcheon hillside. UN Cemetery and Jagalchi are flat. Comfortable walking shoes with grip are essential."},{"id":"family","question":"Is this suitable for families?","answer":"Yes for school-age children (6+) who can manage stairs. Younger children may struggle at Yonggungsa and Gamcheon. The Beach Train at Cheongsapo and the live-fish floor at Jagalchi are reliable kid-pleasers."},{"id":"rain","question":"What if it rains?","answer":"Light rain: tour runs as scheduled. Heavy rain: Yonggungsa''s lower temple area becomes slippery, Gamcheon''s stairs unsafe — the guide may shorten outdoor time and extend the indoor stops (Jagalchi). Typhoon-level: rebooking or full refund."}],"guestReviews":[],"reviewsSummary":{"averageRating":0,"totalReviews":0,"ratingDistribution":[{"stars":5,"count":0,"percentage":0},{"stars":4,"count":0,"percentage":0},{"stars":3,"count":0,"percentage":0},{"stars":2,"count":0,"percentage":0},{"stars":1,"count":0,"percentage":0}],"highlights":[]},"sticky_booking_bar":{"note":"checkout_tour_id resolves at runtime from Supabase / env; not part of static JSONB.","price":{"amountLabel":"","currency":"USD","per":"person","priceNote":"Small-group price not yet confirmed from operator listing. Comparable Busan one-day tours range $41–$70 across operators. Once confirmed, AtoC Korea sale price applies a flat 10% discount."}},"matching_profile":{"profile_version":6,"is_active":true,"product_id":"busan-top-attractions-day-tour","product_type":"small_group","route_type":"fixed_route","destination_region":"korea_mainland","region_type":"busan_city","vehicle_type":"coach","duration_hours":9,"region_tags":["busan_haeundae","busan_gijang","busan_namgu","busan_saha","busan_jung"],"theme_tags":["temple","coastal","war_memorial","mural_village","fish_market","korean_war_history"],"poi_tags":["haedong_yonggungsa","cheongsapo_blue_line_park","un_memorial_cemetery","gamcheon_culture_village","jagalchi_market"],"pace_level":0.7,"walking_level":0.85,"scenic_level":0.9,"photo_level":1,"culture_level":0.95,"relax_level":0.5,"first_time_fit":1,"family_fit":0.85,"senior_fit":0.7,"couple_fit":0.95,"solo_traveler_fit":0.9,"active_traveler_fit":0.8,"adult_family_fit":1,"family_with_teens_fit":0.95,"yo